/** @format */

import { Divider, makeStyles, Paper } from "@material-ui/core";
import React from "react";
import HTML5 from "../imgs/html5.png";
import JSX from "../imgs/react.png";
import sass from "../imgs/sass.svg";
import css3 from "../imgs/css3.png";
import handlebars from "../imgs/handlebars.jpg";
import bootstrap from "../imgs/bootstrap.png";
import material_ui from "../imgs/material_ui.svg";
import javascript from "../imgs/javascript.png";
import nodejs from "../imgs/nodejs.png";
import mysql from "../imgs/MySQL.svg";
import mongodb from "../imgs/mongodb.png";
import vscode from "../imgs/vscode.png";
import vstudio from "../imgs/vstudio.png";
import sublimetext from "../imgs/sublimetext.jfif";
import npm from "../imgs/npm.png";
import API from "../imgs/API.jpg";
import github from "../imgs/github.png";
import DSA from "../imgs/DSA.png";

const useStyles = makeStyles((theme) => ({
    root: {
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        "& > *": {
            margin: theme.spacing(1),
            width: "90vw",
            height: "auto",
        },
    },
}));

const Skills = () => {
    const classes = useStyles();

    return (
        <>
            <div className="my-5" id="skills">
                <div className="container-fluid p-3 color-violet">
                    <h1 className="fw-light text-center">SKILLS</h1>
                </div>

                <div className={`${classes.root} container my-5`}>
                    {/* HTML */}
                    <Paper elevation={5} variant="elevation">
                        <h1 className="mx-3 mx-md-5 my-3 fw-lighter">HTML</h1>
                        <Divider variant="middle" className="divide" />

                        <div className="container-fluid">
                            <div className="row">
                                <div className="d-flex flex-column align-items-center col-4 col-md-2 p-3">
                                    <img
                                        style={{
                                            maxHeight: "100px",
                                            objectFit: "contain",
                                        }}
                                        className="img-fluid"
                                        src={HTML5}
                                        alt="HTML5"
                                    />
                                    <h5 className="text-center fw-lighter mt-2">
                                        HTML5
                                    </h5>
                                </div>
                                <div className="d-flex flex-column align-items-center col-4 col-md-2 p-3">
                                    <img
                                        style={{
                                            maxHeight: "100px",
                                            objectFit: "contain",
                                        }}
                                        className="img-fluid"
                                        src={JSX}
                                        alt="JSX"
                                    />
                                    <h5 className="text-center fw-lighter mt-2">
                                        JSX
                                    </h5>
                                </div>
                                <div className="d-flex flex-column align-items-center col-4 col-md-2 p-3">
                                    <img
                                        style={{
                                            maxHeight: "100px",
                                            objectFit: "contain",
                                        }}
                                        className="img-fluid"
                                        src={handlebars}
                                        alt="HTML5"
                                    />
                                    <h5 className="text-center fw-lighter mt-2">
                                        Handlebars
                                    </h5>
                                </div>
                            </div>
                        </div>
                    </Paper>

                    {/* CSS */}
                    <Paper elevation={5} variant="elevation">
                        <h1 className="mx-3 my-3 fw-lighter">CSS</h1>
                        <Divider variant="middle" className="divide" />
                        <div className="container-fluid">
                            <div className="row">
                                <div className="d-flex flex-column align-items-center col-4 col-md-2 p-3">
                                    <img
                                        style={{
                                            maxHeight: "100px",
                                            objectFit: "contain",
                                        }}
                                        className="img-fluid"
                                        src={css3}
                                        alt="HTML5"
                                    />
                                    <h5 className="text-center fw-lighter mt-2">
                                        CSS3
                                    </h5>
                                </div>
                                <div className="d-flex flex-column align-items-center col-4 col-md-2 p-3">
                                    <img
                                        style={{
                                            maxHeight: "100px",
                                            objectFit: "contain",
                                        }}
                                        className="img-fluid"
                                        src={sass}
                                        alt="JSX"
                                    />
                                    <h5 className="text-center fw-lighter mt-2">
                                        SASS
                                    </h5>
                                </div>
                                <div className="d-flex flex-column align-items-center col-4 col-md-2 p-3">
                                    <img
                                        style={{
                                            maxHeight: "100px",
                                            objectFit: "contain",
                                        }}
                                        className="img-fluid"
                                        src={bootstrap}
                                        alt="JSX"
                                    />
                                    <h5 className="text-center fw-lighter mt-2">
                                        Bootstrap
                                    </h5>
                                </div>
                                <div className="d-flex flex-column align-items-center col-4 col-md-2 p-3">
                                    <img
                                        style={{
                                            maxHeight: "100px",
                                            objectFit: "contain",
                                        }}
                                        className="img-fluid"
                                        src={material_ui}
                                        alt="JSX"
                                    />
                                    <h5 className="text-center fw-lighter mt-2">
                                        Material UI
                                    </h5>
                                </div>
                            </div>
                        </div>
                    </Paper>

                    {/* Javascript */}
                    <Paper elevation={5} variant="elevation">
                        <h1 className="mx-3 my-3 fw-lighter">Javascript</h1>
                        <Divider variant="middle" className="divide" />
                        <div className="container-fluid">
                            <div className="row">
                                <div className="d-flex flex-column align-items-center col-4 col-md-2 p-3">
                                    <img
                                        style={{
                                            maxHeight: "100px",
                                            objectFit: "contain",
                                        }}
                                        className="img-fluid"
                                        src={javascript}
                                        alt="HTML5"
                                    />
                                    <h5 className="text-center fw-lighter mt-2">
                                        Javascript
                                    </h5>
                                </div>
                                <div className="d-flex flex-column align-items-center col-4 col-md-2 p-3">
                                    <img
                                        style={{
                                            maxHeight: "100px",
                                            objectFit: "contain",
                                        }}
                                        className="img-fluid"
                                        src={JSX}
                                        alt="JSX"
                                    />
                                    <h5 className="text-center fw-lighter mt-2">
                                        React JS
                                    </h5>
                                </div>
                                <div className="d-flex flex-column align-items-center col-4 col-md-2 p-3">
                                    <img
                                        style={{
                                            maxHeight: "100px",
                                            objectFit: "contain",
                                        }}
                                        className="img-fluid"
                                        src={nodejs}
                                        alt="JSX"
                                    />
                                    <h5 className="text-center fw-lighter mt-2">
                                        Node JS
                                    </h5>
                                </div>
                            </div>
                        </div>
                    </Paper>

                    {/* Back-End */}
                    <Paper elevation={5} variant="elevation">
                        <h1 className="mx-3 my-3 fw-lighter">Back-End</h1>
                        <Divider variant="middle" className="divide" />
                        <div className="container-fluid">
                            <div className="row">
                                <div className="d-flex flex-column align-items-center col-4 col-md-2 p-3">
                                    <img
                                        style={{
                                            maxHeight: "100px",
                                            objectFit: "contain",
                                        }}
                                        className="img-fluid"
                                        src="https://www.vectorlogo.zone/logos/expressjs/expressjs-icon.svg"
                                        alt="HTML5"
                                    />
                                    <h5 className="text-center fw-lighter mt-2">
                                        Express JS
                                    </h5>
                                </div>
                                <div className="d-flex flex-column align-items-center col-4 col-md-2 p-3">
                                    <img
                                        style={{
                                            maxHeight: "100px",
                                            objectFit: "contain",
                                        }}
                                        className="img-fluid"
                                        src={mongodb}
                                        alt="JSX"
                                    />
                                    <h5 className="text-center fw-lighter mt-2">
                                        MongoDB
                                    </h5>
                                </div>
                                <div className="d-flex flex-column align-items-center col-4 col-md-2 p-3">
                                    <img
                                        style={{
                                            maxHeight: "100px",
                                            objectFit: "contain",
                                        }}
                                        className="img-fluid"
                                        src={mysql}
                                        alt="JSX"
                                    />
                                    <h5 className="text-center fw-lighter mt-2">
                                        MySQL
                                    </h5>
                                </div>
                            </div>
                        </div>
                    </Paper>

                    {/* Platforms */}
                    <Paper elevation={5} variant="elevation">
                        <h1 className="mx-3 my-3 fw-lighter">Platforms</h1>
                        <Divider variant="middle" className="divide" />
                        <div className="container-fluid">
                            <div className="row">
                                <div className="d-flex flex-column align-items-center col-4 col-md-2 p-3">
                                    <img
                                        style={{
                                            maxHeight: "100px",
                                            objectFit: "contain",
                                        }}
                                        className="img-fluid"
                                        src={vscode}
                                        alt="HTML5"
                                    />
                                    <h5 className="text-center fw-lighter mt-2">
                                        VS Code
                                    </h5>
                                </div>
                                <div className="d-flex flex-column align-items-center col-4 col-md-2 p-3">
                                    <img
                                        style={{
                                            maxHeight: "100px",
                                            objectFit: "contain",
                                        }}
                                        className="img-fluid"
                                        src={vstudio}
                                        alt="JSX"
                                    />
                                    <h5 className="text-center fw-lighter mt-2">
                                        Visual Studio
                                    </h5>
                                </div>
                                <div className="d-flex flex-column align-items-center col-4 col-md-2 p-3">
                                    <img
                                        style={{
                                            maxHeight: "100px",
                                            objectFit: "contain",
                                        }}
                                        className="img-fluid"
                                        src={sublimetext}
                                        alt="JSX"
                                    />
                                    <h5 className="text-center fw-lighter mt-2">
                                        Sublime Text
                                    </h5>
                                </div>
                            </div>
                        </div>
                    </Paper>

                    {/* Other */}
                    <Paper elevation={5} variant="elevation">
                        <h1 className="mx-3 my-3 fw-lighter">Other</h1>
                        <Divider variant="middle" className="divide" />
                        <div className="container-fluid">
                            <div className="row">
                                <div className="d-flex flex-column align-items-center col-4 col-md-2 p-3">
                                    <img
                                        style={{
                                            minHeight: "100px",
                                            maxHeight: "100px",
                                            objectFit: "contain",
                                        }}
                                        className="img-fluid"
                                        src={npm}
                                        alt="HTML5"
                                    />
                                    <h5 className="text-center fw-lighter mt-2">
                                        NPM
                                    </h5>
                                </div>
                                <div className="d-flex flex-column align-items-center col-4 col-md-2 p-3">
                                    <img
                                        style={{
                                            maxHeight: "100px",
                                            objectFit: "contain",
                                        }}
                                        className="img-fluid"
                                        src={github}
                                        alt="JSX"
                                    />
                                    <h5 className="text-center fw-lighter mt-2">
                                        Github
                                    </h5>
                                </div>
                                <div className="d-flex flex-column align-items-center col-4 col-md-2 p-3">
                                    <img
                                        style={{
                                            maxHeight: "100px",
                                            objectFit: "contain",
                                        }}
                                        className="img-fluid"
                                        src={API}
                                        alt="JSX"
                                    />
                                    <h5 className="text-center fw-lighter mt-2">
                                        API
                                    </h5>
                                </div>
                                <div className="d-flex flex-column align-items-center col-4 col-md-2 p-3">
                                    <img
                                        style={{
                                            maxHeight: "100px",
                                            objectFit: "contain",
                                        }}
                                        className="img-fluid"
                                        src={DSA}
                                        alt="JSX"
                                    />
                                    <h5 className="text-center fw-lighter mt-2">
                                        Data Structures
                                    </h5>
                                </div>
                            </div>
                        </div>
                    </Paper>
                </div>
            </div>
        </>
    );
};

export default Skills;
