/** @format */

import React from "react";
import { Link } from "react-scroll";
import { makeStyles } from "@material-ui/core/styles";
import AppBar from "@material-ui/core/AppBar";
import MenuIcon from "@material-ui/icons/Menu";
import IconButton from "@material-ui/core/IconButton";
import List from "@material-ui/core/List";
import ListItem from "@material-ui/core/ListItem";
import ListItemIcon from "@material-ui/core/ListItemIcon";
import ListItemText from "@material-ui/core/ListItemText";
import { Drawer, Fab } from "@material-ui/core";
import PersonIcon from "@material-ui/icons/Person";
import TableChartIcon from "@material-ui/icons/TableChart";
import BarChartIcon from "@material-ui/icons/BarChart";
import ImportContactsIcon from "@material-ui/icons/ImportContacts";
import ContactsIcon from "@material-ui/icons/Contacts";
import KeyboardArrowUpIcon from "@material-ui/icons/KeyboardArrowUp";
import PostAddIcon from "@material-ui/icons/PostAdd";
import ScrollTop from "./ScrollTop";
import HideOnScroll from "./HideOnScroll";
import resume from "../resume/resume.pdf";

const drawerWidth = 190;

const useStyles = makeStyles((theme) => ({
    root: {
        flexGrow: 1,
    },
    title: {
        textAlign: "center",
    },
    drawer: {
        [theme.breakpoints.up("sm")]: {
            width: drawerWidth,
            flexShrink: 0,
        },
    },
    appBar: {
        [theme.breakpoints.up("sm")]: {
            width: `calc(100% - ${drawerWidth}px)`,
            marginLeft: drawerWidth,
        },
    },
    menuButton: {
        marginRight: theme.spacing(2),
        [theme.breakpoints.up("sm")]: {
            display: "none",
        },
    },
    // necessary for content to be below app bar
    toolbar: theme.mixins.toolbar,
    drawerPaper: {
        width: drawerWidth,
    },
    content: {
        flexGrow: 1,
        padding: theme.spacing(3),
    },
}));

const MainDrawer = (props) => {
    const { window } = props;
    const classes = useStyles();
    const [mobileOpen, setMobileOpen] = React.useState(false);

    const handleDrawerToggle = () => {
        setMobileOpen(!mobileOpen);
    };

    const drawer = (
        <div>
            <div className={classes.toolbar}>
                <List>
                    <ListItem>
                        <h2>Portfolio</h2>
                    </ListItem>
                </List>
            </div>
            <List>
                <Link to="about" spy={true} smooth={false}>
                    <ListItem button>
                        <ListItemIcon>
                            <PersonIcon style={{ color: "#008073" }} />
                        </ListItemIcon>
                        <ListItemText primary="About" />
                    </ListItem>
                </Link>
                <Link to="projects" spy={true} smooth={false}>
                    <ListItem button>
                        <ListItemIcon>
                            <TableChartIcon style={{ color: "#3F51B5" }} />
                        </ListItemIcon>

                        <ListItemText primary="Projects" />
                    </ListItem>
                </Link>
                <Link to="skills" spy={true} smooth={false}>
                    <ListItem button>
                        <ListItemIcon>
                            <BarChartIcon style={{ color: "#9C27B0" }} />
                        </ListItemIcon>
                        <ListItemText primary="Skills" />
                    </ListItem>
                </Link>
                <Link to="education" spy={true} smooth={false}>
                    <ListItem button>
                        <ListItemIcon>
                            <ImportContactsIcon style={{ color: "#FF9800" }} />
                        </ListItemIcon>
                        <ListItemText primary="Education" />
                    </ListItem>
                </Link>
                <Link to="contact" spy={true} smooth={false}>
                    <ListItem button>
                        <ListItemIcon>
                            <ContactsIcon style={{ color: "#795548" }} />
                        </ListItemIcon>
                        <ListItemText primary="Contact" />
                    </ListItem>
                </Link>
                <a href={resume} download="Neh Jain CV">
                    <ListItem button>
                        <ListItemIcon>
                            <PostAddIcon style={{ color: "#424242" }} />
                        </ListItemIcon>
                        <ListItemText primary="Resume" />
                    </ListItem>
                </a>
            </List>
        </div>
    );

    const container =
        window !== undefined ? () => window().document.body : undefined;

    return (
        <div className={classes.root} id="home">
            <HideOnScroll {...props}>
                <AppBar color="inherit">
                    <div className="container-fluid d-flex flex-row text-center">
                        <div className="mt-2">
                            <IconButton onClick={handleDrawerToggle}>
                                <MenuIcon />
                            </IconButton>
                        </div>
                        <div
                            className="container-fluid text-center"
                            style={{ marginRight: "50px" }}
                        >
                            <span
                                style={{ fontSize: "28px", color: "#008073" }}
                            >
                                Neh Jain <br />
                            </span>
                            <span style={{ color: "#B19D95" }}>
                                Full Stack Developer
                            </span>
                        </div>
                    </div>
                </AppBar>
            </HideOnScroll>

            <Drawer
                container={container}
                variant="temporary"
                open={mobileOpen}
                onClose={handleDrawerToggle}
                classes={{
                    paper: classes.drawerPaper,
                }}
                ModalProps={{
                    keepMounted: true, // Better open performance on mobile.
                }}
            >
                {drawer}
            </Drawer>

            <ScrollTop {...props}>
                <Link
                    onClick={() => {
                        document.documentElement.scrollTop = 0;
                    }}
                    spy={true}
                    smooth={false}
                >
                    <Fab color="secondary" size="medium">
                        <KeyboardArrowUpIcon />
                    </Fab>
                </Link>
            </ScrollTop>
        </div>
    );
};

export default MainDrawer;
